import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { LineChart, ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import { TrendingUp, TrendingDown } from '@mui/icons-material';
import response from './response.json';

interface Cryptocurrency {
  name: string;
  symbol: string;
  currentPrice: number;
  priceChange24h: number;
  priceChangePercent24h: number;
}

interface PriceChartData {
  time: string;
  price: number;
}

interface CryptoTrackerData {
  cryptocurrency: Cryptocurrency;
  priceChart: PriceChartData[];
}

export default function Widget() {
  const cryptoTrackerData = response.data as CryptoTrackerData;
  const { cryptocurrency, priceChart } = cryptoTrackerData;
  const isPositive = cryptocurrency.priceChange24h >= 0;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#303030' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FFB300', mb: 1 }}>
              {cryptocurrency.name} ({cryptocurrency.symbol})
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#FFF' }}>
              ${cryptocurrency.currentPrice.toLocaleString()}
            </Typography>
            <Stack direction="row" alignItems="center" spacing={0.5} sx={{ mt: 0.5 }}>
              {isPositive ? <TrendingUp sx={{ fontSize: 16, color: '#10B981' }} /> : <TrendingDown sx={{ fontSize: 16, color: '#EF4444' }} />}
              <Typography variant="body2" sx={{ color: isPositive ? '#10B981' : '#EF4444' }}>
                ${Math.abs(cryptocurrency.priceChange24h).toFixed(2)} ({cryptocurrency.priceChangePercent24h.toFixed(2)}%)
              </Typography>
            </Stack>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: priceChart.map(pc => pc.price),
                  color: '#FF4081',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: priceChart.map(pc => pc.time),
                  id: 'time',
                },
              ]}
              yAxis={[{ id: 'price' }]}
            >
              <ChartsClipPath id={clipPathId} />
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="time"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsYAxis
                axisId="price"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
